  1→import { Share2, Heart } from 'lucide-react';
  2→import { useState } from 'react';
  3→import { useLikedArticles } from '../contexts/LikedArticlesContext';
  4→
  5→export interface WikiArticle {
  6→    title: string;
  7→    displaytitle: string;
  8→    extract: string;
  9→    pageid: number;
 10→    url: string;
 11→    thumbnail: {
 12→        source: string;
 13→        width: number;
 14→        height: number;
 15→    };
 16→}
 17→
 18→interface WikiCardProps {
 19→    article: WikiArticle;
 20→}
 21→
 22→export function WikiCard({ article }: WikiCardProps) {
 23→    const [imageLoaded, setImageLoaded] = useState(false);
 24→    const { toggleLike, isLiked } = useLikedArticles();
 25→
 26→    // Add debugging log
 27→    console.log('Article data:', {
 28→        title: article.title,
 29→        displaytitle: article.displaytitle,
 30→        pageid: article.pageid
 31→    });
 32→
 33→    const handleShare = async () => {
 34→        if (navigator.share) {
 35→            try {
 36→                await navigator.share({
 37→                    title: article.displaytitle,
 38→                    text: article.extract || '',
 39→                    url: article.url
 40→                });
 41→            } catch (error) {
 42→                console.error('Error sharing:', error);
 43→            }
 44→        } else {
 45→            // Fallback: Copy to clipboard
 46→            await navigator.clipboard.writeText(article.url);
 47→            alert('Link copied to clipboard!');
 48→        }
 49→    };
 50→
 51→    return (
 52→        <div className="h-screen w-full flex items-center justify-center snap-start relative" onDoubleClick={() => toggleLike(article)}>
 53→            <div className="h-full w-full relative">
 54→                {article.thumbnail ? (
 55→                    <div className="absolute inset-0">
 56→                        <img
 57→                            loading="lazy"
 58→                            src={article.thumbnail.source}
 59→                            alt={article.displaytitle}
 60→                            className={`w-full h-full object-cover transition-opacity duration-300 bg-white ${imageLoaded ? 'opacity-100' : 'opacity-0'
 61→                                }`}
 62→                            onLoad={() => setImageLoaded(true)}
 63→                            onError={(e) => {
 64→                                console.error('Image failed to load:', e);
 65→                                setImageLoaded(true); // Show content even if image fails
 66→                            }}
 67→                        />
 68→                        {!imageLoaded && (
 69→                            <div className="absolute inset-0 bg-gray-900 animate-pulse" />
 70→                        )}
 71→                        <div className="absolute inset-0 bg-gradient-to-b from-black/20 to-black/60" />
 72→                    </div>
 73→                ) : (
 74→                    <div className="absolute inset-0 bg-gray-900" />
 75→                )}
 76→                {/* Content container with z-index to ensure it's above the image */}
 77→                <div className="absolute backdrop-blur-xs bg-black/30 bottom-[10vh] left-0 right-0 p-6 text-white z-10">
 78→                    <div className="flex justify-between items-start mb-3">
 79→                        <a
 80→                            href={article.url}
 81→                            target="_blank"
 82→                            rel="noopener noreferrer"
 83→                            className="hover:text-gray-200 transition-colors"
 84→                        >
 85→                            <h2 className="text-2xl font-bold drop-shadow-lg">{article.displaytitle}</h2>
 86→                        </a>
 87→                        <div className="flex gap-2">
 88→                            <button
 89→                                onClick={() => toggleLike(article)}
 90→                                className={`p-2 rounded-full backdrop-blur-sm transition-colors ${isLiked(article.pageid)
 91→                                    ? 'bg-red-500 hover:bg-red-600'
 92→                                    : 'bg-white/10 hover:bg-white/20'
 93→                                    }`}
 94→                                aria-label="Like article"
 95→                            >
 96→                                <Heart
 97→                                    className={`w-5 h-5 ${isLiked(article.pageid) ? 'fill-white' : ''}`}
 98→                                />
 99→                            </button>
100→                            <button
101→                                onClick={handleShare}
102→                                className="p-2 rounded-full bg-white/10 backdrop-blur-sm hover:bg-white/20 transition-colors"
103→                                aria-label="Share article"
104→                            >
105→                                <Share2 className="w-5 h-5" />
106→                            </button>
107→                        </div>
108→                    </div>
109→                    <p className="text-gray-100 mb-4 drop-shadow-lg line-clamp-6">{article.extract}</p>
110→                    <a
111→                        href={article.url}
112→                        target="_blank"
113→                        rel="noopener noreferrer"
114→                        className="inline-block text-white hover:text-gray-200 drop-shadow-lg"
115→                    >
116→                        Read more →
117→                    </a>
118→                </div>
119→            </div>
120→        </div>
121→    );
122→}
